
# Fast port helpers (scripts/PortHelpers.ps1)
$__RepoRootForPorts = Split-Path -Parent $PSScriptRoot
$__PortHelpers = Join-Path $__RepoRootForPorts 'scripts\PortHelpers.ps1'
if (Test-Path -LiteralPath $__PortHelpers) { . $__PortHelpers }
Param([switch]$Headless) $SkipFrontend = $Headless  # --- SOTA Headless Standard --- if ($Headless -and ($Host.UI.RawUI.WindowTitle -notmatch 'Hidden')) {     Start-Process pwsh -ArgumentList '-NoProfile', '-File', $PSCommandPath, '-Headless' -WindowStyle Hidden     exit } $WindowStyle = if ($Headless) { 'Hidden' } else { 'Normal' } # ------------------------------  # Webapp Start - Standardized SOTA (Auto-Repaired V2.5) $WebPort = 10884 $BackendPort = 10885 $ProjectRoot = Split-Path -Parent $PSScriptRoot $StudioPort = 10930 $StudioDir = if ($env:SONGGEN_STUDIO_DIR) { $env:SONGGEN_STUDIO_DIR } else { "D:\Dev\repos\external\SongGeneration-Studio" }  # 1. Kill any process squatting on the ports Write-Host "Checking for port squatters on $WebPort and $BackendPort..." -ForegroundColor Yellow $pids = Get-NetTCPConnection -LocalPort $WebPort, $BackendPort -ErrorAction SilentlyContinue | Where-Object { $_.OwningProcess -gt 4 } | Select-Object -ExpandProperty OwningProcess -Unique foreach ($p in $pids) {     Write-Host "Found squatter (PID: $p). Terminating..." -ForegroundColor Red     try { Stop-Process -Id $p -Force -ErrorAction Stop } catch { Write-Host "Warning: Could not terminate PID $p." -ForegroundColor Gray } }  # 2. Setup Set-Location $PSScriptRoot if (-not (Test-Path "node_modules")) { npm install }  # 2b. SongGeneration-Studio (GPU inference) - required for generation; same `uv` toolchain as this repo $studioListener = Get-NetTCPConnection -LocalPort $StudioPort -State Listen -ErrorAction SilentlyContinue if (-not $studioListener) {     $studioMain = Join-Path $StudioDir "main.py"     if (Test-Path $studioMain) {         Write-Host "Starting SongGeneration-Studio on port $StudioPort (uv run) ..." -ForegroundColor Cyan         $studioCmd = "uv run --directory '$StudioDir' python main.py --host 127.0.0.1 --port $StudioPort"         Start-Process powershell -ArgumentList "-NoExit", "-Command", $studioCmd -WindowStyle Normal         $sw = 0         while ($sw -lt 90) {             Start-Sleep -Seconds 1             if (Get-NetTCPConnection -LocalPort $StudioPort -State Listen -ErrorAction SilentlyContinue) { break }             $sw++         }     } else {         Write-Host "SongGeneration-Studio not found at $StudioDir - set SONGGEN_STUDIO_DIR or clone Studio; generation will fail until Studio is up." -ForegroundColor Yellow     } } else {     Write-Host "SongGeneration-Studio already listening on port $StudioPort." -ForegroundColor Green }  # 3. Start the Python backend (Background) from project root - same pattern as other fleet MCP web_sota servers Write-Host "Starting Python backend on port $BackendPort ..." -ForegroundColor Cyan $backendCmd = "`$env:PYTHONPATH = '$ProjectRoot\src'; Set-Location '$ProjectRoot'; uv run --project '$ProjectRoot' uvicorn songgeneration_mcp.server:app --host 127.0.0.1 --port $BackendPort --log-level info" Start-Process powershell -ArgumentList "-NoExit", "-Command", $backendCmd -WindowStyle Normal  # 3b. Wait until the API actually serves HTTP (TCP Listen alone can race or false-positive; Vite proxies need a real response) $healthUrl = "http://127.0.0.1:$BackendPort/api/health" $maxAttempts = 40 $attempt = 0 $backendUp = $false Start-Sleep -Seconds 1 while ($attempt -lt $maxAttempts) {     try {         $r = Invoke-WebRequest -Uri $healthUrl -UseBasicParsing -TimeoutSec 3 -ErrorAction Stop         if ($r.StatusCode -eq 200) {             $backendUp = $true             break         }     } catch {         # connection refused / still starting     }     Start-Sleep -Seconds 2     $attempt++ } if ($backendUp) {     Write-Host "Backend (port $BackendPort) answered GET /api/health - ready for Vite proxy." -ForegroundColor Green } else {     Write-Host "Backend (port $BackendPort) did not return HTTP 200 from /api/health after $($maxAttempts * 2)s. Open the uvicorn PowerShell window for errors." -ForegroundColor Yellow }  # 4. Run server (Vite dev) Write-Host "Starting Vite frontend on port $WebPort ..." -ForegroundColor Green  # 4b. Launch background task to open browser once frontend is ready (Auto-opened by Antigravity) $frontendUrl = "http://127.0.0.1:$WebPort/" $pollAndOpen = "for (`$i = 0; `$i -lt 60; `$i++) { try { `$null = Invoke-WebRequest -Uri '$frontendUrl' -TimeoutSec 2 -UseBasicParsing -ErrorAction Stop; Start-Process '$frontendUrl'; exit } catch { Start-Sleep -Seconds 1 } }" Start-Process powershell -ArgumentList "-NoProfile", "-WindowStyle", "Hidden", "-Command", $pollAndOpen  Write-Host "Browser will open automatically when Vite is ready." -ForegroundColor Gray if ($SkipFrontend) { return } npm run dev -- --port $WebPort --host  
